INSERT INTO knowledge_base (category, question, answer, keywords) VALUES
-- WiFi
('IT', 'What is the campus WiFi password?', 'The campus WiFi network is "Adamas-WiFi". Connect with your roll number and portal password. For guests, ask at the reception for a temporary pass.', 'wifi password network internet connection wireless'),
('IT', 'How do I connect to the campus WiFi?', 'Go to WiFi settings, select "Adamas-WiFi", enter your roll number as username and your portal password. Accept the certificate if prompted.', 'wifi connect setup network'),

-- Library
('Library', 'What are the library hours?', 'The central library is open Monday-Saturday 8:00 AM to 8:00 PM. Sunday 10:00 AM to 4:00 PM. During exams, it stays open until 10:00 PM.', 'library hours open close timing'),
('Library', 'How do I borrow books from the library?', 'Use your student ID card at the library counter. You can borrow up to 3 books for 14 days. Renew online through the library portal.', 'library borrow books checkout'),
('Library', 'Does the library have digital resources?', 'Yes, access e-books, journals, and databases through the library portal using your roll number. Available 24/7 from any campus network.', 'library digital online e-books journals'),

-- Cafeteria
('Campus Life', 'Where is the cafeteria?', 'The main cafeteria is on the ground floor of the Academic Block. There is also a food court near the hostel block and a cafe in the library building.', 'cafeteria food canteen eating lunch'),
('Campus Life', 'What are the cafeteria timings?', 'The cafeteria is open from 7:30 AM to 7:30 PM on weekdays. Saturday 8:00 AM to 2:00 PM. Closed on Sundays.', 'cafeteria hours timing food'),

-- Academics
('Academics', 'When are the semester exams?', 'Odd semester exams are typically in November-December. Even semester exams are in April-May. Check the academic calendar on the portal for exact dates.', 'exams semester final schedule'),
('Academics', 'How do I check my grades?', 'Log in to the student portal, go to Academic Records > View Grades. Your CGPA and semester GPAs are displayed there.', 'grades gpa cgpa results marks academic'),
('Academics', 'How do I apply for revaluation?', 'Apply through the portal within 2 weeks of result declaration. Pay the revaluation fee online. Results are updated within 30 days.', 'revaluation recheck marks grade appeal'),
('Academics', 'What is the attendance policy?', 'Minimum 75% attendance is required to be eligible for semester exams. Medical leave requires proper documentation submitted to the HR department.', 'attendance absent present leave policy'),

-- Hostel
('Hostel', 'How do I apply for hostel accommodation?', 'Apply through the hostel section on the student portal during the admission period. Allotment is based on distance from home and availability.', 'hostel accommodation room stay'),
('Hostel', 'What are the hostel timings?', 'Hostel gate closes at 10:00 PM for all students. Late entry requires warden permission. Weekend curfew is 11:00 PM.', 'hostel timing curfew gate'),

-- Transport
('Transport', 'Is there a campus bus service?', 'Yes, buses run on major routes across the city. Check the transport section on the portal for route maps and timings.', 'bus transport route commute'),
('Transport', 'How do I get a bus pass?', 'Apply online through the transport portal. Pay the semester fee. Your bus pass will be linked to your student ID.', 'bus pass transport commute'),

-- Placements
('Placements', 'When do campus placements start?', 'Placement season typically starts in August for final year students. Pre-placement talks begin in July. Check the placement portal for company schedules.', 'placement job career interview'),
('Placements', 'How do I register for placements?', 'Register on the placement portal when registration opens. Complete your profile, upload resume, and apply for companies you are eligible for.', 'placement register sign up career'),

-- General
('General', 'What is the student portal URL?', 'The student portal is at https://student.adamas.edu.in. Log in with your roll number and password.', 'portal website login url'),
('General', 'How do I contact the administration?', 'Visit the Admin Block, Room 101, or email admin@adamas.edu.in. Phone: 033-2351-1000. Working hours: 9 AM to 5 PM.', 'admin contact phone email address'),
('General', 'Where can I find the academic calendar?', 'The academic calendar is available on the student portal under Academics > Calendar. It is updated at the start of each semester.', 'academic calendar schedule date');
